external_knowledge:
- 'half of the average standard deviation of wall time' refers to 0.5 * AVG(i.std_wall_time); 
- 'running instances' refers to instances with a status of 'running'; 
- 'average wall time' refers to AVG(i.wall_time).

sql:
SELECT i.instance_id, m.metric_name, m.value, m.timestamp, m.unit
FROM instances i
LEFT JOIN performance_metrics m ON i.instance_id = m.instance_id;

SELECT instance_id, set_id
FROM instances
WHERE std_wall_time > (
    SELECT AVG(std_wall_time) FROM instances
);

SELECT i.instance_id, i.set_id, i.std_wall_time
FROM instances i
WHERE i.std_wall_time > (SELECT AVG(std_wall_time) FROM instances);

SELECT i.instance_id, i.set_id, i.tenant_id
FROM instances i
WHERE i.status = 'running' AND i.wall_time > (
    SELECT AVG(wall_time) FROM instances WHERE status = 'running'
);

external_knowledge:
; Performance metrics refer to the values in the performance_metrics table, which is used to measure the performance of instances; 
; Instance refers to a unique entity with an instance_id; 
; Set refers to a group of instances with a set_id; 
; Tenant refers to an entity that owns instances, identified by a tenant_id.
